#include<bits/stdc++.h>
using namespace std;
int x[5050],y[5050],n;
double dis[5010];
bool vis[5050];
double dist(int i,int j)
{
    return sqrt(1ll*(x[i]-x[j])*(x[i]-x[j])+1ll*(y[i]-y[j])*(y[i]-y[j]));
}
void prim()
{
    for(int i=1;i<=n;i++)
    {
        dis[i]=1e15;
    }
    dis[1]=0;
    for(int i=1;i<=n;i++)
    {
        double min1=1e15;
        int min2;
        for(int j=1;j<=n;j++)
        {
            if(!vis[j]&&dis[j]<min1)
            {
                min1=dis[j];
                min2=j;
            }
        }
        vis[min2]=1;
        for(int j=1;j<=n;j++)
        {
            if(!vis[j]&&dist(min2,j)<dis[j])
            {
                dis[j]=dist(min2,j);
            }
        }
    }
}
int main()
{
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d%d",&x[i],&y[i]);
    }
    prim();
    double ans=0;
    for(int i=1;i<=n;i++)
    {
        ans+=dis[i];
    }
    printf("%.2lf",ans);
    return 0;
}
